const fixedColumns = [
    "drawingId", "date", "childId", "child_status", "colors_used", 
    "color_count", "dominant_color", "color_temperature", "color_variety", 
    "elements_found", "person_count", "is_self_portrait", "character_size", 
    "family_complete", "drawing_position", "drawing_size", "line_fluidity", 
    "pen_pressure", "skill_level", "cognitive_level", "drawing_story", 
    "age_appropriate", "happiness_index", "emotional_state", "joy_sources", 
    "warning_level", "violence_index", "depression_index", "total_score", 
    "development_stage"
];

// 2. الوصول للنص من المسار الذي حددته
const rawText = $input.first().json.content.parts[0].text;

try {
    // 3. تحويل النص القادم من جيميناي إلى Object
    const data = JSON.parse(rawText);

    // 4. استخراج القيم بترتيب الأعمدة الثابتة
    const orderedValues = fixedColumns.map(col => {
        // نضع القيمة الموجودة، وإذا لم توجد نضع "غير محدد" كما في البرومبت
        return (data[col] !== undefined) ? data[col] : "غير محدد";
    });

    // 5. إرجاع النتيجة (للأعمدة والقيم)
    return {
        columns: fixedColumns,
        orderedValues: orderedValues,
        // سطر جاهز للنسخ واللصق اليدوي في شيت (مفصول بـ Tab)
        clipboardReady: orderedValues.join('\t') 
    };

} catch (error) {
    return {
        error: "فشل في تحليل النص، تأكد أن جيميناي أرجع JSON صحيح",
        details: error.message
    };
}

