};

const groqResponse = $input.first().json;

// استخراج تحليل الـ LLM
let llm = {};
try {
  const content = groqResponse?.choices?.[0]?.message?.content;
  llm = JSON.parse(content);
} catch(e) {}

// بناء كلمات البحث بناءً على الحالة
const emotion = llm.dominant_state || 'تطوير الطفل';
const needed  = llm.most_needed   || 'أنشطة تعليمية';

const youtubeQueries = [
  `child art therapy ${emotion}`,
  `kids emotional development activities`,
  `${needed} children support`
];

// إضافة الـ queries على الـ response الأصلي وإرجاعه
return {
  ...groqResponse,
  youtube_queries: youtubeQueries,
  youtube_search_url: `https://www.youtube.com/results?search_query=${encodeURIComponent(youtubeQueries[0])}`
};
